It turns out there were bugs; need to use 32 bit integer but they were using long, which on x86_64 is 8 byte, which caused havoc
```C
#include <stdio.h>
#include <math.h>
#include <stdint.h>
#include <xmmintrin.h>


static inline void sse_rsqrt( float * restrict pOut, float * restrict pIn )
{
   __m128 in = _mm_load_ss( pIn );
   _mm_store_ss( pOut, _mm_rsqrt_ss( in ) );
}

// plus one newton raphson step
static inline void sse_rsqrt_nr( float * restrict pOut, float * restrict pIn )
{
    const float threehalfs = 1.5F;
    float y, x2;

    x2 = *pIn * 0.5F;

    __m128 in = _mm_load_ss( pIn );
    _mm_store_ss( &y, _mm_rsqrt_ss( in ) );

    *pOut  = y * ( threehalfs - ( x2 * y * y ) );
}


float carmack_rsqrt( float number )
{
    int32_t i;
    float x2, y;
    const float threehalfs = 1.5F;

    x2 = number * 0.5F;
    y  = number;
    i  = * ( int32_t * ) &y;
    i  = 0x5f3759df - ( i >> 1 );
    y  = * ( float * ) &i;
    y  = y * ( threehalfs - ( x2 * y * y ) );

    return y;
}

// with extra newton raphson step
float carmack_rsqrt_nr2( float number )
{
    int32_t i;
    float x2, y;
    const float threehalfs = 1.5F;

    x2 = number * 0.5F;
    y  = number;
    i  = * ( int32_t * ) &y;
    i  = 0x5f3759df - ( i >> 1 );
    y  = * ( float * ) &i;
    y  = y * ( threehalfs - ( x2 * y * y ) );
    y  = y * ( threehalfs - ( x2 * y * y ) );

    return y;
}



int main(int argc, char** argv)
{

    float x = atof(argv[1]);

    float r, rc, rc2, rsse, rssenr;

    printf("sizeof(long): %d\n", sizeof(long));

    r = 1.0/sqrt(x);
    rc  = carmack_rsqrt(x);
    rc2 = carmack_rsqrt_nr2(x);

    sse_rsqrt(&rsse, &x);
    sse_rsqrt_nr(&rssenr, &x);

    printf("carmack 1 nr: %g %g %.16g\n", r, rc, (double)rc/(double)r-1.0);
    printf("carmack 2 nr: %g %g %.16g\n", r, rc2, (double)rc2/(double)r-1.0);
    printf("sse:          %g %g %.16g\n", r, rsse, (double)rsse/(double)r-1.0);
    printf("sse:    1nr   %g %g %.16g\n", r, rssenr, (double)rssenr/(double)r-1.0);


}
```

